import React, { useState } from 'react';

export default function CreditCardForm() {
  const [number, setNumber] = useState("");
  const [name, setName] = useState("");
  const [expiry, setExpiry] = useState("");
  const [cvc, setCvc] = useState("");
  const [isFlipped, setIsFlipped] = useState(false);

  const handleNumberChange = (e) => {
    const value = e.target.value.replace(/\D/g, '').substring(0, 16);
    const formatted = value.match(/.{1,4}/g)?.join(' ') || '';
    setNumber(formatted);
  };

  const handleExpiryChange = (e) => {
    const value = e.target.value.replace(/\D/g, '').substring(0, 4);
    const formatted = value.length > 2 ? `${value.substring(0, 2)}/${value.substring(2)}` : value;
    setExpiry(formatted);
  };

  const handleCvcChange = (e) => {
    const value = e.target.value.replace(/\D/g, '').substring(0, 3);
    setCvc(value);
  };

  return (
    <div className="flex flex-col md:flex-row items-center gap-10 max-w-3xl mx-auto py-10 font-sans">
      {/* 3D Visual Card Preview */}
      <div className="w-80 h-48 [perspective:1000px] relative select-none">
        <div className={`w-full h-full relative transition-transform duration-500 [transform-style:preserve-3d] ${isFlipped ? '[transform:rotateY(180deg)]' : ''}`}>
          {/* Card Front */}
          <div className="absolute inset-0 w-full h-full rounded-2xl bg-gradient-to-tr from-purple-700 to-indigo-500 p-6 text-white flex flex-col justify-between shadow-xl backface-hidden">
            <div className="flex justify-between items-center">
              <span className="text-xs font-bold uppercase tracking-widest">DevWar Pay</span>
              <svg className="w-8 h-8 opacity-80" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm0 18c-4.41 0-8-3.59-8-8s3.59-8 8-8 8 3.59 8 8-3.59 8-8 8z" /></svg>
            </div>
            <div className="text-xl font-mono tracking-widest my-4">
              {number || "•••• •••• •••• ••••"}
            </div>
            <div className="flex justify-between text-xs font-medium uppercase">
              <div>
                <span className="block text-[10px] text-purple-200">Holder</span>
                <span>{name || "UMANG SISODIA"}</span>
              </div>
              <div>
                <span className="block text-[10px] text-purple-200">Expires</span>
                <span>{expiry || "MM/YY"}</span>
              </div>
            </div>
          </div>

          {/* Card Back */}
          <div className="absolute inset-0 w-full h-full rounded-2xl bg-gradient-to-tr from-purple-800 to-indigo-600 shadow-xl backface-hidden [transform:rotateY(180deg)] py-6">
            <div className="w-full h-10 bg-black mt-2" />
            <div className="px-6 mt-4">
              <span className="block text-[10px] text-purple-200 uppercase">CVC</span>
              <div className="w-full bg-white text-gray-800 text-right pr-3 font-mono py-1 rounded font-bold">
                {cvc || "•••"}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Inputs Form */}
      <div className="w-80 flex flex-col gap-4">
        <div>
          <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Card Number</label>
          <input type="text" placeholder="1234 5678 1234 5678" value={number} onChange={handleNumberChange} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm outline-none focus:border-purple-500" />
        </div>
        <div>
          <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Holder Name</label>
          <input type="text" placeholder="UMANG SISODIA" value={name} onChange={(e) => setName(e.target.value.substring(0, 20))} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm outline-none focus:border-purple-500" />
        </div>
        <div className="flex gap-4">
          <div className="w-1/2">
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Expiry</label>
            <input type="text" placeholder="MM/YY" value={expiry} onChange={handleExpiryChange} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm outline-none focus:border-purple-500" />
          </div>
          <div className="w-1/2">
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">CVC</label>
            <input type="text" placeholder="123" value={cvc} onChange={handleCvcChange} onFocus={() => setIsFlipped(true)} onBlur={() => setIsFlipped(false)} className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm outline-none focus:border-purple-500" />
          </div>
        </div>
      </div>
      <style>{`
        .backface-hidden {
          backface-visibility: hidden;
          -webkit-backface-visibility: hidden;
        }
      `}</style>
    </div>
  );
}
